# 安全库存约束
for m in materials:
    for t in periods:
        model += I[m, t] >= safety_stock[m], f"SS_{m}_{t}"

# Lead time 偏移的库存平衡
for m in materials:
    lt = lead_time[m]
    for t in periods:
        order_period = t - lt + 1
        if order_period >= 0:
            inflow = x[m, order_period]
        else:
            inflow = 0  # 初始期前的订单视为已到货（初始库存覆盖）
        model += I[m,t] == I[m,t-1] + inflow - consumed[m,t]
